function c = xcorr(a,b,maxlag,flag)%XCORR Calculate autocorrelation function%%	Syntax%%	  C = XCORR(A,B,MAXLAG,'flag')%%	Description%	%    XCORR(A,B,MAXLAG,'flag') %    normalizes the correlation according to 'flag':%        biased   - scales the raw cross-correlation by 1/N.%        unbiased - scales the raw correlation by 1/(N-abs(k)), where k %                   is the index into the result.%        coeff    - normalizes the sequence so that the correlations at %                   zero lag are identically 1.0.%        none     - no scaling (this is the default).%		%	Examples%%	  This code generates an autoregressive sequence.%	%	    e = randn(1,2000);%	    y = filter(1,[1 -.8],e);%%	  The following command generates the autocorrelation functions.%	  The acf will be computed from lag -20 to lag 20.   %%	    yacf = xcorr(y,y,20,'unbiased');%% Yong Hu, Martin Hagan, 10-05-00% $Revision: 1.0 $ $Date: 05-Oct-2000 00:50:00 $if nargin<3, maxlag = 20; endif nargin<4, flag = 'none'; endif ~isstr(flag)	error('FLAG should be a string');enda = makerow(a);b = makerow(b);n = length(a);n1 = length(b);if maxlag>=n    error('MAXLAG should be less than the lengths of A and B.');endif n~=n1	error('The lengths of A and B should be equal.');endc = zeros(1,2*maxlag-1);for i=0:maxlag   ac = a(1:(n-i))*b(1+i:n)';   if i==0,	   ac0=ac;   end   switch (flag)     case 'unbiased',		 ac = ac/(n-i);     case 'biased',		 ac = ac/n;	 case 'coeff',		 ac = ac/ac0;   end      c(1,maxlag+1+i) = ac;   c(1,maxlag+1-i) = ac;end